import React, { useState, useEffect } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { useJobs } from '../context/JobContext';
import { FaArrowLeft, FaEdit, FaTrash, FaBuilding, FaBriefcase, FaCalendar, FaStickyNote, FaLink, FaExternalLinkAlt } from 'react-icons/fa';

function JobDetails() {
   const { id } = useParams();
  const navigate = useNavigate();
  const { getJob, updateJob, deleteJob } = useJobs();
  const [job, setJob] = useState(null);
  const [isEditing, setIsEditing] = useState(false);
  const [formData, setFormData] = useState({});
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);

  // Load job data on component mount
  // Load job data on component mount
useEffect(() => {
    const foundJob = getJob(id);
    if (foundJob) {
      setJob(foundJob);
      setFormData(foundJob);
      if (window.location.pathname.includes('/edit/')) {
        setIsEditing(true);
      }
    } else {
      navigate('/');
    }
  }, [id, navigate, getJob]);

  const getStatusColor = (status) => {
    const colors = {
      'Applied': 'bg-blue-100 text-blue-800',
      'Interviewing': 'bg-yellow-100 text-yellow-800',
      'Offer': 'bg-green-100 text-green-800',
      'Rejected': 'bg-red-100 text-red-800'
    };
    return colors[status] || 'bg-gray-100 text-gray-800';
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleUpdate = () => {
    const jobs = JSON.parse(localStorage.getItem('jobs') || '[]');
    const updatedJobs = jobs.map(j => 
      j.id === id ? { ...formData } : j
    );
    localStorage.setItem('jobs', JSON.stringify(updatedJobs));
    setJob(formData);
    setIsEditing(false);
  };

  const handleDelete = () => {
    const jobs = JSON.parse(localStorage.getItem('jobs') || '[]');
    const filteredJobs = jobs.filter(j => j.id !== id);
    localStorage.setItem('jobs', JSON.stringify(filteredJobs));
    navigate('/');
  };

  if (!job) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-purple-600 mx-auto"></div>
          <p className="mt-4 text-gray-600">Loading job details...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="container mx-auto px-4 max-w-4xl">
        {/* Back Button */}
        <button
          onClick={() => navigate('/')}
          className="mb-6 flex items-center text-gray-600 hover:text-purple-600 transition"
        >
          <FaArrowLeft className="mr-2" />
          Back to Dashboard
        </button>

        {/* Main Card */}
        <div className="bg-white rounded-lg shadow-lg overflow-hidden">
          {/* Header with Status */}
          <div className="bg-gradient-to-r from-purple-600 to-purple-800 px-6 py-4">
            <div className="flex justify-between items-start">
              <div>
                <h1 className="text-2xl font-bold text-white mb-1">{job.company}</h1>
                <p className="text-purple-200">{job.position}</p>
              </div>
              <span className={`px-4 py-2 rounded-full text-sm font-semibold ${getStatusColor(job.status)}`}>
                {job.status}
              </span>
            </div>
          </div>

          {/* Content */}
          <div className="p-6">
            {!isEditing ? (
              /* View Mode */
              <div className="space-y-6">
                {/* Job Details Grid */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="flex items-start space-x-3">
                    <FaBuilding className="text-purple-600 mt-1" />
                    <div>
                      <p className="text-sm text-gray-500">Company</p>
                      <p className="text-lg font-semibold text-gray-800">{job.company}</p>
                    </div>
                  </div>
                  
                  <div className="flex items-start space-x-3">
                    <FaBriefcase className="text-purple-600 mt-1" />
                    <div>
                      <p className="text-sm text-gray-500">Position</p>
                      <p className="text-lg font-semibold text-gray-800">{job.position}</p>
                    </div>
                  </div>
                  
                  <div className="flex items-start space-x-3">
                    <FaCalendar className="text-purple-600 mt-1" />
                    <div>
                      <p className="text-sm text-gray-500">Application Date</p>
                      <p className="text-lg font-semibold text-gray-800">
                        {new Date(job.date).toLocaleDateString('en-US', { 
                          weekday: 'long', 
                          year: 'numeric', 
                          month: 'long', 
                          day: 'numeric' 
                        })}
                      </p>
                    </div>
                  </div>
                  
                  <div className="flex items-start space-x-3">
                    <div className={`px-3 py-1 rounded-full ${getStatusColor(job.status)}`}>
                      {job.status}
                    </div>
                  </div>
                </div>

                {/* Job Link */}
                {job.link && (
                  <div className="border-t border-gray-100 pt-4">
                    <div className="flex items-start space-x-3">
                      <FaLink className="text-purple-600 mt-1" />
                      <div className="flex-1">
                        <p className="text-sm text-gray-500 mb-1">Job Posting Link</p>
                        <a 
                          href={job.link}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="text-purple-600 hover:text-purple-800 flex items-center gap-1 break-all"
                        >
                          {job.link}
                          <FaExternalLinkAlt size={12} />
                        </a>
                      </div>
                    </div>
                  </div>
                )}

                {/* Notes */}
                {job.notes && (
                  <div className="border-t border-gray-100 pt-4">
                    <div className="flex items-start space-x-3">
                      <FaStickyNote className="text-purple-600 mt-1" />
                      <div className="flex-1">
                        <p className="text-sm text-gray-500 mb-1">Notes</p>
                        <p className="text-gray-700 whitespace-pre-wrap">{job.notes}</p>
                      </div>
                    </div>
                  </div>
                )}

                {/* Action Buttons */}
                <div className="flex justify-end gap-4 pt-6 border-t border-gray-200">
                  <button
                    onClick={() => setIsEditing(true)}
                    className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition flex items-center gap-2"
                  >
                    <FaEdit />
                    Edit
                  </button>
                  <button
                    onClick={() => setShowDeleteConfirm(true)}
                    className="px-6 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 transition flex items-center gap-2"
                  >
                    <FaTrash />
                    Delete
                  </button>
                </div>
              </div>
            ) : (
              /* Edit Mode */
              <div className="space-y-6">
                <h2 className="text-xl font-bold text-gray-800 mb-4">Edit Application</h2>
                
                {/* Edit Form */}
                <div className="space-y-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">Company *</label>
                    <input
                      type="text"
                      name="company"
                      value={formData.company}
                      onChange={handleChange}
                      className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500"
                    />
                  </div>

                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">Position *</label>
                    <input
                      type="text"
                      name="position"
                      value={formData.position}
                      onChange={handleChange}
                      className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500"
                    />
                  </div>

                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">Job Link</label>
                    <input
                      type="url"
                      name="link"
                      value={formData.link || ''}
                      onChange={handleChange}
                      className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500"
                    />
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">Status</label>
                      <select
                        name="status"
                        value={formData.status}
                        onChange={handleChange}
                        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500"
                      >
                        <option value="Applied">Applied</option>
                        <option value="Interviewing">Interviewing</option>
                        <option value="Offer">Offer</option>
                        <option value="Rejected">Rejected</option>
                      </select>
                    </div>

                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">Date</label>
                      <input
                        type="date"
                        name="date"
                        value={formData.date}
                        onChange={handleChange}
                        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500"
                      />
                    </div>
                  </div>

                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">Notes</label>
                    <textarea
                      name="notes"
                      value={formData.notes || ''}
                      onChange={handleChange}
                      rows="4"
                      className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500"
                    />
                  </div>
                </div>

                {/* Edit Mode Buttons */}
                <div className="flex justify-end gap-4 pt-4">
                  <button
                    onClick={() => setIsEditing(false)}
                    className="px-6 py-2 border border-gray-300 rounded-lg text-gray-700 hover:bg-gray-50 transition"
                  >
                    Cancel
                  </button>
                  <button
                    onClick={handleUpdate}
                    className="px-6 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 transition"
                  >
                    Save Changes
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Delete Confirmation Modal */}
        {showDeleteConfirm && (
          <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50">
            <div className="bg-white rounded-lg p-6 max-w-md w-full">
              <h3 className="text-xl font-bold text-gray-800 mb-4">Delete Application</h3>
              <p className="text-gray-600 mb-6">
                Are you sure you want to delete the application for <span className="font-semibold">{job.company}</span>? 
                This action cannot be undone.
              </p>
              <div className="flex justify-end gap-4">
                <button
                  onClick={() => setShowDeleteConfirm(false)}
                  className="px-4 py-2 border border-gray-300 rounded-lg text-gray-700 hover:bg-gray-50 transition"
                >
                  Cancel
                </button>
                <button
                  onClick={handleDelete}
                  className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 transition"
                >
                  Delete
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default JobDetails;
